            role: String,
            content: String,
        }
        if let Ok(turns) = resp.take::<Vec<ChatTurn>>(0) {
            for turn in turns {
                let turn_str = format!("- **{}**: {}\n", if turn.role == "user" { "User" } else { "Assistant" }, turn.content);
